import {
  Box,
  Button,
  Flex,
  FormControl,
  FormLabel,
  Grid,
  Input,
  Textarea,
} from "@chakra-ui/react";
import React, { useState } from "react";
import "./edit.css";
import AdminNavTop from "../AdminNavTop";
import { useDispatch, useSelector } from "react-redux";
import { useNavigate, useParams } from "react-router-dom";
import { patchProduct } from "../../Redux/AdminReducer/action";

const EditPage = () => {
  const backgroundImageUrl =
    "https://png.pngtree.com/background/20211217/original/pngtree-blue-round-technology-dashboard-picture-image_1598386.jpg";

  const { id } = useParams();
  const dispatch = useDispatch();
  const store = useSelector((store) => store.AdminReducer.data);
  console.log(store);
  const existedUser = store.filter((el) => el._id == id);
  // console.log("existedUser",existedUser)
  const navigate = useNavigate();

  console.log(existedUser);

  // console.log(id)

  let obj = {
    title: existedUser[0]?.title,
    description: existedUser[0]?.description,
    category: existedUser[0]?.category,
    price: existedUser[0]?.price,
    teacher: existedUser[0]?.teacher,
    img: existedUser[0]?.img || "",
  };

  // console.log("obj",obj)
  const [detail, setDetail] = useState(obj);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setDetail((prev) => {
      return { ...prev, [name]: value };
    });
  };

  const handleSubmit = () => {
    //  console.log(detail);
    dispatch(patchProduct(id, detail));
    alert("Data Updated Successfully");
    navigate("/admin/courses");
  };

  return (
  <Box bg="#f7f9fa" minH="100vh" p={6}>
    <AdminNavTop />

    <Box
      maxW="700px"
      mx="auto"
      mt="80px"
      bg="white"
      p={8}
      borderRadius="lg"
      boxShadow="lg"
    >
      {/* TITLE */}
      <Text fontSize="2xl" fontWeight="bold" mb={6}>
        Edit Course
      </Text>

      <FormControl mb={4}>
        <FormLabel>Title</FormLabel>
        <Input
          name="title"
          value={detail?.title}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={4}>
        <FormLabel>Description</FormLabel>
        <Textarea
          name="description"
          value={detail?.description}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={4}>
        <FormLabel>Category</FormLabel>
        <Input
          name="category"
          value={detail?.category}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={4}>
        <FormLabel>Price</FormLabel>
        <Input
          type="number"
          name="price"
          value={detail?.price}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={4}>
        <FormLabel>Instructor</FormLabel>
        <Input
          name="teacher"
          value={detail?.teacher}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={6}>
        <FormLabel>Thumbnail</FormLabel>
        <Input
          name="img"
          value={detail?.img}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      {/* PREVIEW */}
      {detail?.img && (
        <Box mb={6}>
          <img
            src={detail.img}
            style={{ borderRadius: 8, width: "100%" }}
          />
        </Box>
      )}

      <Button
        bg="#A435F0"
        color="white"
        size="lg"
        w="100%"
        _hover={{ bg: "#8710d8" }}
        onClick={handleSubmit}
      >
        Update Course
      </Button>
    </Box>
  </Box>
);
};

export default EditPage;
